import React, {useState, useEffect} from "react";
import { Link } from "react-router-dom";
import "./advicedetailCSS.css";
import Navbaremployee from "./upperlistemployee";
import Cookies from "universal-cookie";

export const AdviceDetail = () => {
    const [search, setSearch] = useState('');
    const cookies=new Cookies();
    
    useEffect(() => {
        cookies.set('search',search,{path:'/'});
        console.log(cookies)
    },[search])

    return(
        <>
            <Navbaremployee setSearch={setSearch}/>
            <div className="customerinfo">
                <p className="title">顧客資訊</p>
                <div className="name">
                    <p className="label">姓名</p>
                    <p className="input">嘿嘿嘿</p>
                </div>
                <div className="sex">
                    <p className="label">性別</p>
                    <p className="input">嘿嘿嘿</p>
                </div>
                <div className="phone">
                    <p className="label">連絡電話</p>
                    <p className="input">嘿嘿嘿</p>
                </div>
                <div className="email">
                    <p className="label">E-mail</p>
                    <p className="input">嘿嘿嘿</p>
                </div>
                <div className="cinema">
                    <p className="label">影城分店</p>
                    <p className="input">嘿嘿嘿</p>
                </div>
            </div>
            <div className="advicecontent">
                <p className="title">建議內容</p>
                <p className="content">以下省略</p>
            </div>
            <div className="advicereply">
                <p className="title">信件回覆</p>
                <p className="reply">以下省略</p>
            </div>
        </>
    );
};
export default AdviceDetail;
